 89	void set_Lmax(NR_DL_FRAME_PARMS *fp) {
 90	  // definition of Lmax according to ts 38.213 section 4.1
 91	  if (fp->dl_CarrierFreq < 6e9) {
 92	    if(fp->frame_type && (fp->ssb_type==2))
 93	      fp->Lmax = (fp->dl_CarrierFreq < 2.4e9)? 4 : 8;
 94	    else
