101	int nr_get_ssb_start_symbol(const NR_DL_FRAME_PARMS *fp, uint8_t i_ssb)
102	{
103	  int mu = fp->numerology_index;
104	  int symbol = 0;
105	  uint8_t n, n_temp;
106	  nr_ssb_type_e type = fp->ssb_type;
107	  int case_AC[2] = {2,8};
108	  int case_BD[4] = {4,8,16,20};
109	  int case_E[8] = {8, 12, 16, 20, 32, 36, 40, 44};
110	
111	  switch(mu) {
112	    case NR_MU_0: // case A
113	      n = i_ssb >> 1;
114	      symbol = case_AC[i_ssb % 2] + 14*n;
115	      break;
116	    case NR_MU_1:
117	      if (type == 1){ // case B
118	        n = i_ssb >> 2;
119	        symbol = case_BD[i_ssb % 4] + 28*n;
120	       }
121	       if (type == 2){ // case C
122	         n = i_ssb >> 1;
123	         symbol = case_AC[i_ssb % 2] + 14*n;
124	       }
125	       break;
126	     case NR_MU_3: // case D
127	       n_temp = i_ssb >> 2;
128	       n = n_temp + (n_temp >> 2);
129	       symbol = case_BD[i_ssb % 4] + 28*n;
130	       break;
131	     case NR_MU_4:  // case E
132	       n_temp = i_ssb >> 3;
133	       n = n_temp + (n_temp >> 2);
134	       symbol = case_E[i_ssb % 8] + 56*n;
135	       break;
136	     default:
137	       AssertFatal(0==1, "Invalid numerology index %d for the synchronization block\n", mu);
138	  }
139	
140	  return symbol;
141	}
