143	void set_scs_parameters (NR_DL_FRAME_PARMS *fp, int mu, int N_RB_DL)
144	{
145	  int idx = 0;
146	  switch(mu) {
147	    case NR_MU_0: //15kHz scs
148	      fp->subcarrier_spacing = nr_subcarrier_spacing[NR_MU_0];
149	      fp->slots_per_subframe = nr_slots_per_subframe[NR_MU_0];
150	      fp->ssb_type = nr_ssb_type_A;
151	      while (nr_ssb_table[idx][0] != fp->nr_band)
152	        idx++;
153	      AssertFatal(nr_ssb_table[idx][1] == 15,"SCS %d not applicable to band %d\n",
154	                  fp->subcarrier_spacing,fp->nr_band);
155	      break;
156	
157	    case NR_MU_1: //30kHz scs
158	      fp->subcarrier_spacing = nr_subcarrier_spacing[NR_MU_1];
159	      fp->slots_per_subframe = nr_slots_per_subframe[NR_MU_1];
160	      while(nr_ssb_table[idx][0] != fp->nr_band ||
161	            nr_ssb_table[idx][1] != 30) {
162	        AssertFatal(nr_ssb_table[idx][0] <= fp->nr_band,
163	                    "SCS %d not applicable to band %d\n",
164	                    fp->subcarrier_spacing,
165	                    fp->nr_band);
166	        idx++;
167	      }
168	      fp->ssb_type = nr_ssb_table[idx][2];
169	      break;
170	
171	    case NR_MU_2: //60kHz scs
172	      fp->subcarrier_spacing = nr_subcarrier_spacing[NR_MU_2];
173	      fp->slots_per_subframe = nr_slots_per_subframe[NR_MU_2];
174	      break;
175	
176	    case NR_MU_3:
177	      fp->subcarrier_spacing = nr_subcarrier_spacing[NR_MU_3];
178	      fp->slots_per_subframe = nr_slots_per_subframe[NR_MU_3];
179	      fp->ssb_type = nr_ssb_type_D;
180	      break;
181	
182	    case NR_MU_4:
183	      fp->subcarrier_spacing = nr_subcarrier_spacing[NR_MU_4];
184	      fp->slots_per_subframe = nr_slots_per_subframe[NR_MU_4];
185	      fp->ssb_type = nr_ssb_type_E;
186	      break;
187	
188	    default:
189	      AssertFatal(1==0,"Invalid numerology index %d", mu);
190	  }
191	
192	  if(fp->threequarter_fs)
193	    fp->ofdm_symbol_size = 3 * 128;
194	  else
195	    fp->ofdm_symbol_size = 4 * 128;
196	
197	  while(fp->ofdm_symbol_size < N_RB_DL * 12)
198	    fp->ofdm_symbol_size <<= 1;
199	
200	  fp->first_carrier_offset = fp->ofdm_symbol_size - (N_RB_DL * 12 / 2);

